import { client } from "@trigger.dev/sdk";

// Initialize the Trigger.dev client
// Note: In production, you would set TRIGGER_SECRET_KEY in your environment
const triggerClient = client({ id: "agent-project" });

// Trial ID from /logs/trial_id
const TRIAL_ID = "complex_agent_orchestration__j3GRqpT";

// Define the queue with concurrency limit of 2
const agentQueue = triggerClient.defineQueue({
  id: `agent-queue-${TRIAL_ID}`,
  concurrencyLimit: 2,
});

// Main research agent task
export const researchAgent = triggerClient.defineJob({
  id: `researchAgent-${TRIAL_ID}`,
  name: "Research Agent",
  queue: agentQueue,
  run: async (payload, { ctx, trigger }) => {
    const { query, depth = 1 } = payload;

    console.log(`Research Agent - Depth: ${depth}, Query: ${query}`);

    // Step 1: Check depth limit
    if (depth > 2) {
      console.log("Max depth reached");
      return {
        status: "max_depth_reached",
        result: "Max depth reached",
        depth,
        query,
      };
    }

    // Step 2: Trigger search sub-task
    console.log(`Triggering search task for: ${query}`);
    const searchResult = await triggerAndWait(
      ctx,
      searchTask,
      {
        query,
        depth,
      }
    );

    console.log(`Search result: ${JSON.stringify(searchResult)}`);

    // Step 3: Check if result contains "insufficient"
    if (searchResult.result && searchResult.result.includes("insufficient")) {
      console.log("Insufficient results, recursing with refined query");

      // Refined query for recursion
      const refinedQuery = `${query} detailed comprehensive`;

      // Step 4: Recursively trigger researchAgent with depth + 1
      const recursiveResult = await triggerAndWait(
        ctx,
        researchAgent,
        {
          query: refinedQuery,
          depth: depth + 1,
        }
      );

      return {
        status: "recursed",
        result: recursiveResult.result,
        originalQuery: query,
        refinedQuery,
        depth: depth + 1,
        searchResult: searchResult.result,
      };
    }

    // Step 5: Return final result
    console.log("Sufficient results found, returning final result");
    return {
      status: "completed",
      result: searchResult.result,
      query,
      depth,
    };
  },
});

// Search sub-task
export const searchTask = triggerClient.defineJob({
  id: `searchTask-${TRIAL_ID}`,
  name: "Search Task",
  run: async (payload, { ctx }) => {
    const { query, depth } = payload;

    console.log(`Search Task - Query: ${query}, Depth: ${depth}`);

    // Simulate search operation
    // In a real implementation, this would call an actual search API
    await new Promise(resolve => setTimeout(resolve, 100));

    // Simulate different results based on query content
    // For demonstration, we'll return "insufficient" for certain queries
    const insufficientKeywords = ["basic", "simple", "quick"];
    const hasInsufficientKeyword = insufficientKeywords.some(keyword => 
      query.toLowerCase().includes(keyword)
    );

    if (hasInsufficientKeyword) {
      return {
        status: "insufficient",
        result: `Search results for "${query}" are insufficient. More detailed search needed.`,
        query,
        depth,
      };
    }

    return {
      status: "success",
      result: `Comprehensive search results for "${query}": Found detailed information matching your query.`,
      query,
      depth,
    };
  },
});

// Helper function for triggerAndWait
async function triggerAndWait<T>(
  ctx: any,
  job: any,
  payload: any
): Promise<T> {
  // Trigger the job and wait for completion
  const result = await job.triggerAndWait(payload, {
    id: `${job.id}-${Date.now()}`,
  });

  return result as T;
}

