  query: string;      // The research query
  depth?: number;     // Current recursion depth (default: 1)
  depth: number | undefined
}
```

**Execution Flow**:

1. **Depth Check** (Lines 24-30):
   ```typescript
   if (depth > 2) {
     return {
       status: "max_depth_reached",
       result: "Max depth reached",
       depth,
       query,
     };
   }
   ```
   - Prevents infinite recursion
   - Returns immediately if depth exceeds limit

2. **Search Trigger** (Lines 32-39):
   ```typescript
   const searchResult = await triggerAndWait(
     ctx,
     searchTask,
     { query, depth }
   );
   ```
   - Triggers `searchTask` sub-task
   - Waits for completion
   - Captures result for evaluation

3. **Result Evaluation** (Lines 41-57):
   ```typescript
   if (searchResult.result && searchResult.result.includes("insufficient")) {
     const refinedQuery = `${query} detailed comprehensive`;
     const recursiveResult = await triggerAndWait(
       ctx,
       researchAgent,
       { query: refinedQuery, depth: depth + 1 }
     );
     return { /* recursive result */ };
   }
   ```
   - Checks for "insufficient" keyword in results
   - Refines query with additional keywords
   - Recursively triggers with incremented depth

4. **Final Return** (Lines 59-67):
   ```typescript
   return {
     status: "completed",
     result: searchResult.result,
     query,
     depth,
   };
   ```
   - Returns successful result
   - Includes query and depth for tracking

### 3. Search Task

```typescript
export const searchTask = triggerClient.defineJob({
  id: `searchTask-${TRIAL_ID}`,
  name: "Search Task",
  run: async (payload, { ctx }) => {
    // Implementation
  },
});
```

**Payload Schema**:
```typescript
interface SearchTaskPayload {
  query: string;
  depth: number;
}
```

**Logic**:

```typescript
// Simulate search delay
await new Promise(resolve => setTimeout(resolve, 100));

// Check for insufficient keywords
const insufficientKeywords = ["basic", "simple", "quick"];
const hasInsufficientKeyword = insufficientKeywords.some(keyword => 
  query.toLowerCase().includes(keyword)
);

// Return appropriate result
if (hasInsufficientKeyword) {
  return {
    status: "insufficient",
    result: `Search results for "${query}" are insufficient...`,
    query,
    depth,
  };
}

return {
  status: "success",
  result: `Comprehensive search results for "${query}"...`,
  query,
  depth,
};
```

**Insufficient Keywords**: `basic`, `simple`, `quick`

### 4. triggerAndWait Helper

```typescript
async function triggerAndWait<T>(
  ctx: any,
  job: any,
  payload: any
): Promise<T> {
  const result = await job.triggerAndWait(payload, {
    id: `${job.id}-${Date.now()}`,
  });
  return result as T;
}
```

**Purpose**: Type-safe wrapper for Trigger.dev's `triggerAndWait` method.

**Features**:
- Generates unique execution IDs
- Provides type safety with generics
- Handles async execution

## Concurrency Control

### Queue Behavior

The `agent-queue` with `concurrencyLimit: 2` ensures:

```
Time →
┌─────┬─────┬─────┬─────┬─────┬─────┐
│ A1  │ A2  │ B1  │ A3  │ B2  │ C1  │
└─────┴─────┴─────┴─────┴─────┴─────┘
  ↑           ↑           ↑
  Running     Running    Running
  (max 2)     (max 2)    (max 2)

A1, A2 = Agent 1, 2 (concurrent)
B1 = Agent 3 (waiting)
A3 = Agent 1 completes, Agent 3 starts
B2 = Agent 2 completes, Agent 4 starts
C1 = Agent 3 completes, Agent 5 starts
```

### Thread Safety

- Queue provides atomic execution guarantees
- No race conditions between concurrent agents
- Deterministic execution order

## Recursion Patterns

### Pattern 1: Successful Recursion

```
researchAgent("basic research", depth=1)
  └─> searchTask("basic research", depth=1)
      └─> Result: "insufficient"
          └─> researchAgent("basic research detailed comprehensive", depth=2)
              └─> searchTask("basic research detailed comprehensive", depth=2)
                  └─> Result: "success"
                      └─> Return final result
```

### Pattern 2: Immediate Success

```
researchAgent("comprehensive analysis", depth=1)
  └─> searchTask("comprehensive analysis", depth=1)
      └─> Result: "success"
          └─> Return immediately
```

### Pattern 3: Max Depth Reached

```
researchAgent("any query", depth=3)
  └─> depth > 2 check
      └─> Return "Max depth reached"
```

## State Management

### Execution Context

Each task execution maintains:

```typescript
interface ExecutionContext {
  // Trigger context
  ctx: {
    id: string;
    attempt: number;
    timestamp: Date;
  };

  // Payload
  payload: {
    query: string;
    depth: number;
  };

  // Trigger function
  trigger: {
    triggerAndWait: Function;
  };
}
```

### Result Tracking

Results include complete execution history:

```typescript
interface ResearchResult {
  status: "completed" | "recursed" | "max_depth_reached";
  result: string;
  query: string;
  depth: number;
  originalQuery?: string;
  refinedQuery?: string;
  searchResult?: string;
}
```

## Error Handling

### Built-in Protections

1. **Depth Limit**: Prevents stack overflow from infinite recursion
2. **Queue Limit**: Prevents resource exhaustion from too many concurrent agents
3. **Timeout**: Search tasks have built-in timeout protection
4. **Type Safety**: TypeScript ensures correct payload structures

### Error Scenarios

| Scenario | Behavior |
|----------|----------|
| Depth > 2 | Returns "Max depth reached" |
| Queue full | Task waits in queue |
| Search timeout | Task fails with timeout error |
| Invalid payload | TypeScript compilation error |

