const mockTrigger = {
  triggerAndWait: async (job: any, payload: any) => {
    // Simulate triggerAndWait behavior
    if (job.id.includes("searchTask")) {
      return await searchTask.run(payload, { ctx: mockCtx });
    }
    if (job.id.includes("researchAgent")) {
      return await researchAgent.run(payload, { 
        ctx: mockCtx, 
        trigger: mockTrigger 
      });
    }
    throw new Error("Unknown job");
  },
};

describe("Research Agent", () => {
  describe("Depth Limit", () => {
    it("should return max depth reached when depth > 2", async () => {
      const result = await researchAgent.run(
        { query: "test query", depth: 3 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("max_depth_reached");
      expect(result.result).toBe("Max depth reached");
      expect(result.depth).toBe(3);
    });

    it("should execute normally when depth <= 2", async () => {
      const result = await researchAgent.run(
        { query: "comprehensive analysis", depth: 1 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("completed");
      expect(result.depth).toBe(1);
    });
  });

  describe("Recursion Logic", () => {
    it("should recurse when search result contains 'insufficient'", async () => {
      const result = await researchAgent.run(
        { query: "basic research", depth: 1 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("recursed");
      expect(result.depth).toBe(2);
      expect(result.originalQuery).toBe("basic research");
      expect(result.refinedQuery).toContain("detailed");
      expect(result.refinedQuery).toContain("comprehensive");
    });

    it("should not recurse when search result is sufficient", async () => {
      const result = await researchAgent.run(
        { query: "comprehensive analysis", depth: 1 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("completed");
      expect(result.depth).toBe(1);
      expect(result.result).toContain("Comprehensive search results");
    });
  });

  describe("Default Depth", () => {
    it("should use default depth of 1 when not provided", async () => {
      const result = await researchAgent.run(
        { query: "comprehensive analysis" },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.depth).toBe(1);
    });
  });
});

describe("Search Task", () => {
  describe("Insufficient Detection", () => {
    it("should return insufficient for queries with 'basic'", async () => {
      const result = await searchTask.run(
        { query: "basic research", depth: 1 },
        { ctx: mockCtx }
      );

      expect(result.status).toBe("insufficient");
      expect(result.result).toContain("insufficient");
    });

    it("should return insufficient for queries with 'simple'", async () => {
      const result = await searchTask.run(
        { query: "simple explanation", depth: 1 },
        { ctx: mockCtx }
      );

      expect(result.status).toBe("insufficient");
      expect(result.result).toContain("insufficient");
    });

    it("should return insufficient for queries with 'quick'", async () => {
      const result = await searchTask.run(
        { query: "quick overview", depth: 1 },
        { ctx: mockCtx }
      );

      expect(result.status).toBe("insufficient");
      expect(result.result).toContain("insufficient");
    });

    it("should be case-insensitive for insufficient keywords", async () => {
      const result = await searchTask.run(
        { query: "BASIC research", depth: 1 },
        { ctx: mockCtx }
      );

      expect(result.status).toBe("insufficient");
    });
  });

  describe("Success Cases", () => {
    it("should return success for queries without insufficient keywords", async () => {
      const result = await searchTask.run(
        { query: "comprehensive analysis", depth: 1 },
        { ctx: mockCtx }
      );

      expect(result.status).toBe("success");
      expect(result.result).toContain("Comprehensive search results");
    });

    it("should include query in result", async () => {
      const query = "detailed investigation";
      const result = await searchTask.run(
        { query, depth: 1 },
        { ctx: mockCtx }
      );

      expect(result.result).toContain(query);
      expect(result.query).toBe(query);
    });

    it("should include depth in result", async () => {
      const depth = 2;
      const result = await searchTask.run(
        { query: "test query", depth },
        { ctx: mockCtx }
      );

      expect(result.depth).toBe(depth);
    });
  });

  describe("Async Behavior", () => {
    it("should simulate async delay", async () => {
      const start = Date.now();
      await searchTask.run(
        { query: "test query", depth: 1 },
        { ctx: mockCtx }
      );
      const end = Date.now();

      expect(end - start).toBeGreaterThanOrEqual(100);
    });
  });
});

describe("Integration Tests", () => {
  describe("Full Workflow", () => {
    it("should complete full recursion workflow", async () => {
      const result = await researchAgent.run(
        { query: "basic research", depth: 1 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("recursed");
      expect(result.depth).toBe(2);
      expect(result.result).toBeDefined();
    });

    it("should complete simple workflow without recursion", async () => {
      const result = await researchAgent.run(
        { query: "comprehensive analysis", depth: 1 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("completed");
      expect(result.depth).toBe(1);
    });

    it("should handle max depth scenario", async () => {
      const result = await researchAgent.run(
        { query: "any query", depth: 3 },
        { ctx: mockCtx, trigger: mockTrigger }
      );

      expect(result.status).toBe("max_depth_reached");
      expect(result.result).toBe("Max depth reached");
    });
  });
});

